import _ from 'lodash';
const MemoizedComponent = ({ data }) => {
  const [count, setCount] = useState(0);
  useEffect(() => {
    const isEqual = _.isEqual(data, prevData);
    if (!isEqual) setCount(new Date().getTime());
  }, [data, prevData]);
  return <div>Count: {count}</div>;
};

solutions.python:
import json
from functools import lru_cache
class MemoizedComponent:
  def __init__(self, data):
    self.data = data
    self.count = 0
  def render(self):
    @lru_cache(maxsize=None)
    def isEqual(data1, data2):
      return json.dumps(data1, sort_keys=True) == json.dumps(data2, sort_keys=True)
    if not isEqual(self.data, self.prevData):
      self.count += 1
    self.prevData = self.data
    return f"Count: {self.count}"
